# Python uses indentation to define code blocks

# Example 1: If-else with indentation
age = 18

if age >= 18:
    print("Adult")      # Indented 4 spaces - inside 'if' block
    print("Can vote")   # Also inside 'if' block
else:
    print("Minor")     # Indented 4 spaces - inside 'else' block
    print("Cannot vote")

# Example 2: Nested blocks
score = 85

if score >= 60:
    print("Passed")
    if score >= 80:
        print("Grade: A")    # Nested inside inner 'if'
        print("Excellent!")
    else:
        print("Grade: B")
else:
    print("Failed")

# Example 3: Loop with nested condition
for i in range(3):
    print(f"Iteration {i}:")    # Inside 'for' loop
    if i % 2 == 0:
        print(f"  {i} is even")   # Inside both 'for' and 'if'
    else:
        print(f"  {i} is odd")
